// ─────── Token validation (LOG-ONLY, reverted 2026-05-29) ────────
// Aircall sends Authorization: Bearer <token> with the token configured in
// Aircall Dashboard → Integrations → Public API. Mismatch is logged but
// the workflow continues — per the project rule (rules.md §C): ship new
// security checks in log-only mode FIRST, flip to enforce only after
// confirming zero false flags in production logs. Initial flip-to-enforce
// on 2026-05-29 was premature; reverted to log-only the same day.
//
// To finalize enforcement: watch n8n executions for 24-48h, confirm every
// legitimate Aircall webhook arrives with a matching Bearer token, then
// replace `console.warn` below with `throw new Error(...)`.
//
// TODO: rotate this token + move to n8n Credentials (currently hardcoded).
try {
  const EXPECTED_TOKEN = '7f4a9322925a44c588cd14e2f91f4b43';
  const headers = $input.first().json.headers || {};
  const authHeader = headers.authorization || headers.Authorization || '';
  const presentedToken = authHeader.replace(/^Bearer\s+/i, '').trim();
  if (presentedToken !== EXPECTED_TOKEN) {
    console.warn('[aircall-webhook] token mismatch (log-only):', {
      hasHeader: !!authHeader,
      presentedLength: presentedToken.length,
      receivedAt: new Date().toISOString(),
    });
  }
} catch (tokenCheckErr) {
  console.warn('[aircall-webhook] token check error (log-only):', tokenCheckErr.message);
}
